import React, { FC, ReactElement } from 'react';
import { Button, message } from 'antd';
import {useTranslation} from '@spotter/i18n-sdk';
import { UseCompatibleDecoratorOptions, useCompatibleDecorator } from './useCompatibleDecorator';
import { useNetworkDecorator } from './useNetworkDecorator';


const OFFLINE_HELP_MESSAGE = 'OFFLINE_HELP_MESSAGE';
const BROWSER_TIP_CLOSE_KEY = 'BROWSER_TIP_CLOSE_KEY';

export const SpotterAppDecorator: FC<{ children: ReactElement;getConfig:UseCompatibleDecoratorOptions['getConfig'] }> = ({ children, getConfig }) => {
    const {t} = useTranslation();
    useCompatibleDecorator({
        onUnsupportedVersion: () => {
            message.warning({
                content: (
                    <span className="leading-16px flex items-center">
                        <span className="mr-12px">{t('common.supported_browser_version_tip')}</span>
                        <Button
                            style={{
                                padding: 6,
                            }}
                            onClick={() => {
                                message.destroy(BROWSER_TIP_CLOSE_KEY);
                            }}
                            type="link"
                        >
                            {t('common.action_close')}
                        </Button>
                    </span>
                ),
                duration: 0,
                key: BROWSER_TIP_CLOSE_KEY,
            });
        },
        onUnsupportedBrowser: () => {
            message.warning({
                content: (
                    <span className="leading-16px flex items-center">
                        <span className="mr-12px">{t('common.supported_browser_tip')}</span>
                        <Button
                            style={{
                                padding: 6,
                            }}
                            onClick={() => {
                                message.destroy(BROWSER_TIP_CLOSE_KEY);
                            }}
                            type="link"
                        >
                            {t('common.action_close')}
                        </Button>
                    </span>
                ),
                duration: 0,
                key: BROWSER_TIP_CLOSE_KEY,
            })
        },
        getConfig
    });
    useNetworkDecorator({
        onNetworkChange: (isOnline) => {
            if (!isOnline) {
                message.error({
                    content: (
                        <span className="leading-16px flex items-center">
                            <span className="mr-12px">{t('infra.network_goes_offline_tips')}</span>
                            <Button
                                style={{
                                    padding: 6,
                                }}
                                onClick={() => {
                                    message.destroy(OFFLINE_HELP_MESSAGE);
                                }}
                                type="link"
                            >
                                {t('common.action_close')}
                            </Button>
                        </span>
                    ),
                    duration: 0,
                    key: OFFLINE_HELP_MESSAGE,
                });
            } else {
                message.destroy(OFFLINE_HELP_MESSAGE);
            }
        },
        emitOfflineWhenRouteChange: false,
    });
    return children;
};
